551→// the resolution set by the interval.
552→func (ng *Engine) NewRangeQuery(ctx context.Context, q storage.Queryable, opts QueryOpts, qs string, start, end time.Time, interval time.Duration) (Query, error) {
553→	pExpr, qry := ng.newQuery(q, qs, opts, start, end, interval)
554→	finishQueue, err := ng.queueActive(ctx, qry)
555→	if err != nil {
556→		return nil, err
557→	}
558→	defer finishQueue()
559→	expr, err := ng.parser.ParseExpr(qs)
560→	if err != nil {
561→		return nil, err
562→	}
563→	if err := ng.validateOpts(expr); err != nil {
564→		return nil, err
565→	}
566→	if expr.Type() != parser.ValueTypeVector && expr.Type() != parser.ValueTypeScalar {
567→		return nil, fmt.Errorf("invalid expression type %q for range query, must be Scalar or instant Vector", parser.DocumentedType(expr.Type()))
568→	}
569→	*pExpr, err = PreprocessExpr(expr, start, end, interval)
570→
571→	return qry, err
572→}
