577→	}
578→
579→	lookbackDelta := opts.LookbackDelta()
580→	if lookbackDelta <= 0 {
581→		lookbackDelta = ng.lookbackDelta
582→	}
583→
584→	es := &parser.EvalStmt{
585→		Start:         start,
586→		End:           end,
587→		Interval:      interval,
588→		LookbackDelta: lookbackDelta,
589→	}
590→	qry := &query{
591→		q:           qs,
592→		stmt:        es,
593→		ng:          ng,
594→		stats:       stats.NewQueryTimers(),
595→		sampleStats: stats.NewQuerySamples(ng.enablePerStepStats && opts.EnablePerStepStats()),
596→		queryable:   q,
597→	}
598→	return &es.Expr, qry
