605→
606→func (ng *Engine) validateOpts(expr parser.Expr) error {
607→	if ng.enableAtModifier && ng.enableNegativeOffset {
608→		return nil
609→	}
610→
611→	var atModifierUsed, negativeOffsetUsed bool
612→
613→	var validationErr error
614→	parser.Inspect(expr, func(node parser.Node, _ []parser.Node) error {
615→		switch n := node.(type) {
616→		case *parser.VectorSelector:
617→			if n.Timestamp != nil || n.StartOrEnd == parser.START || n.StartOrEnd == parser.END {
618→				atModifierUsed = true
619→			}
620→			if n.OriginalOffset < 0 {
621→				negativeOffsetUsed = true
622→			}
623→
624→		case *parser.MatrixSelector:
625→			vs := n.VectorSelector.(*parser.VectorSelector)
626→			if vs.Timestamp != nil || vs.StartOrEnd == parser.START || vs.StartOrEnd == parser.END {
627→				atModifierUsed = true
628→			}
629→			if vs.OriginalOffset < 0 {
630→				negativeOffsetUsed = true
631→			}
632→
633→		case *parser.SubqueryExpr:
634→			if n.Timestamp != nil || n.StartOrEnd == parser.START || n.StartOrEnd == parser.END {
635→				atModifierUsed = true
636→			}
637→			if n.OriginalOffset < 0 {
638→				negativeOffsetUsed = true
639→			}
640→		}
641→
642→		if atModifierUsed && !ng.enableAtModifier {
643→			validationErr = ErrValidationAtModifierDisabled
644→			return validationErr
645→		}
646→		if negativeOffsetUsed && !ng.enableNegativeOffset {
647→			validationErr = ErrValidationNegativeOffsetDisabled
648→			return validationErr
