358→			return nil, annotations.New().Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
359→		}
360→	}
361→
362→	h := last.CopyToSchema(minSchema)
363→	// This subtraction may deliberately include conflicting counter resets.
364→	// Counter resets are treated explicitly in this function, so the
365→	// information about conflicting counter resets is ignored here.
366→	_, _, nhcbBoundsReconciled, err := h.Sub(prev)
367→	if err != nil {
368→		if errors.Is(err, histogram.ErrHistogramsIncompatibleSchema) {
369→			return nil, annotations.New().Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(labels), pos))
