427→func instantValue(vals Matrix, args parser.Expressions, out Vector, isRate bool) (Vector, annotations.Annotations) {
428→	var (
429→		samples = vals[0]
430→		ss      = make([]Sample, 0, 2)
431→		annos   annotations.Annotations
432→	)
433→
434→	// No sense in trying to compute a rate without at least two points. Drop
435→	// this Vector element.
436→	// TODO: add RangeTooShortWarning
437→	if len(samples.Floats)+len(samples.Histograms) < 2 {
438→		return out, nil
439→	}
440→
441→	// Add the last 2 float samples if they exist.
442→	for i := max(0, len(samples.Floats)-2); i < len(samples.Floats); i++ {
443→		ss = append(ss, Sample{
444→			F: samples.Floats[i].F,
445→			T: samples.Floats[i].T,
446→		})
447→	}
448→
449→	// Add the last 2 histogram samples into their correct position if they exist.
450→	for i := max(0, len(samples.Histograms)-2); i < len(samples.Histograms); i++ {
451→		s := Sample{
452→			H: samples.Histograms[i].H,
453→			T: samples.Histograms[i].T,
454→		}
455→		switch {
456→		case len(ss) == 0:
457→			ss = append(ss, s)
458→		case len(ss) == 1:
459→			if s.T < ss[0].T {
460→				ss = append([]Sample{s}, ss...)
461→			} else {
462→				ss = append(ss, s)
463→			}
464→		case s.T < ss[0].T:
465→			// s is older than 1st, so discard it.
466→		case s.T > ss[1].T:
467→			// s is newest, so add it as 2nd and make the old 2nd the new 1st.
468→			ss[0] = ss[1]
469→			ss[1] = s
470→		default:
471→			// In all other cases, we just make s the new 1st.
472→			// This establishes a correct order, even in the (irregular)
473→			// case of equal timestamps.
474→			ss[0] = s
475→		}
476→	}
477→
478→	resultSample := ss[1]
479→	sampledInterval := ss[1].T - ss[0].T
480→	if sampledInterval == 0 {
481→		// Avoid dividing by 0.
482→		return out, nil
483→	}
484→	switch {
485→	case ss[1].H == nil && ss[0].H == nil:
486→		if !isRate || !(ss[1].F < ss[0].F) {
487→			// Gauge, or counter without reset, or counter with NaN value.
488→			resultSample.F = ss[1].F - ss[0].F
489→		}
490→
491→		// In case of a counter reset, we leave resultSample at
492→		// its current value, which is already ss[1].
493→	case ss[1].H != nil && ss[0].H != nil:
494→		resultSample.H = ss[1].H.Copy()
495→		// irate should only be applied to counters.
496→		if isRate && (ss[1].H.CounterResetHint == histogram.GaugeType || ss[0].H.CounterResetHint == histogram.GaugeType) {
497→			annos.Add(annotations.NewNativeHistogramNotCounterWarning(getMetricName(samples.Metric), args.PositionRange()))
498→		}
499→		// idelta should only be applied to gauges.
500→		if !isRate && (ss[1].H.CounterResetHint != histogram.GaugeType || ss[0].H.CounterResetHint != histogram.GaugeType) {
501→			annos.Add(annotations.NewNativeHistogramNotGaugeWarning(getMetricName(samples.Metric), args.PositionRange()))
502→		}
503→		if !isRate || !ss[1].H.DetectReset(ss[0].H) {
504→			// This subtraction may deliberately include conflicting
505→			// counter resets. Counter resets are treated explicitly
506→			// in this function, so the information about
507→			// conflicting counter resets is ignored here.
508→			_, _, nhcbBoundsReconciled, err := resultSample.H.Sub(ss[0].H)
509→			if errors.Is(err, histogram.ErrHistogramsIncompatibleSchema) {
510→				return out, annos.Add(annotations.NewMixedExponentialCustomHistogramsWarning(getMetricName(samples.Metric), args.PositionRange()))
511→			}
512→			if nhcbBoundsReconciled {
513→				annos.Add(annotations.NewMismatchedCustomBucketsHistogramsInfo(args.PositionRange(), annotations.HistogramSub))
514→			}
515→		}
516→		resultSample.H.CounterResetHint = histogram.GaugeType
517→		resultSample.H.Compact(0)
518→	default:
519→		// Mix of a float and a histogram.
520→		return out, annos.Add(annotations.NewMixedFloatsHistogramsWarning(getMetricName(samples.Metric), args.PositionRange()))
521→	}
522→
523→	if isRate {
524→		// Convert to per-second.
525→		if resultSample.H == nil {
526→			resultSample.F /= float64(sampledInterval) / 1000
527→		} else {
528→			resultSample.H.Div(float64(sampledInterval) / 1000)
529→		}
530→	}
531→
532→	return append(out, resultSample), annos
533→}
