535→// Calculate the trend value at the given index i in raw data d.
536→// This is somewhat analogous to the slope of the trend at the given index.
537→// The argument "tf" is the trend factor.
538→// The argument "s0" is the computed smoothed value.
539→// The argument "s1" is the computed trend factor.
540→// The argument "b" is the raw input value.
541→func calcTrendValue(i int, tf, s0, s1, b float64) float64 {
542→	if i == 0 {
543→		return b
544→	}
545→
546→	x := tf * (s1 - s0)
547→	y := (1 - tf) * b
548→
549→	return x + y
550→}
