1355→func (enh *EvalNodeHelper) getOrCreateLblsWithQuantile(lbls labels.Labels, quantileLabel string, q float64) labels.Labels {
1356→	if enh.signatureToLabelsWithQuantile == nil {
1357→		enh.signatureToLabelsWithQuantile = make(map[string]map[float64]labels.Labels)
1358→	}
1359→
1360→	enh.lblBuf = lbls.Bytes(enh.lblBuf)
1361→	cachedLbls, ok := enh.signatureToLabelsWithQuantile[string(enh.lblBuf)]
1362→	if !ok {
1363→		cachedLbls = make(map[float64]labels.Labels, len(enh.quantileStrs))
1364→		enh.signatureToLabelsWithQuantile[string(enh.lblBuf)] = cachedLbls
1365→	}
1366→
1367→	cachedLblsWithQuantile, ok := cachedLbls[q]
1368→	if !ok {
1369→		quantileStr := "NaN"
1370→		if !math.IsNaN(q) {
1371→			// Cannot do map lookup by NaN key.
1372→			quantileStr = enh.quantileStrs[q]
1373→		}
1374→		cachedLblsWithQuantile = labels.NewBuilder(lbls).
1375→			Set(quantileLabel, quantileStr).
1376→			Labels()
1377→
1378→		cachedLbls[q] = cachedLblsWithQuantile
1379→	}
1380→
1381→	return cachedLblsWithQuantile
1382→}
