1384→// rangeEval evaluates the given expressions, and then for each step calls
1385→// the given funcCall with the values computed for each expression at that
1386→// step. The return value is the combination into time series of all the
1387→// function call results.
1388→// The matching (if provided) can be used to prepare the helper
1389→// for each series, then passed to each call funcCall.
1390→func (ev *evaluator) rangeEval(ctx context.Context, matching *parser.VectorMatching, funcCall func([]Vector, Matrix, [][]EvalSeriesHelper, *EvalNodeHelper) (Vector, annotations.Annotations), exprs ...parser.Expr) (Matrix, annotations.Annotations) {
1391→	numSteps := int((ev.endTimestamp-ev.startTimestamp)/ev.interval) + 1
1392→	matrixes := make([]Matrix, len(exprs))
1393→	origMatrixes := make([]Matrix, len(exprs))
1394→	originalNumSamples := ev.currentSamples
1395→	useSignatures := matching != nil
1396→
1397→	var warnings annotations.Annotations
1398→	for i, e := range exprs {
1399→		// Functions will take string arguments from the expressions, not the values.
1400→		if e != nil && e.Type() != parser.ValueTypeString {
1401→			// ev.currentSamples will be updated to the correct value within the ev.eval call.
1402→			val, ws := ev.eval(ctx, e)
1403→			warnings.Merge(ws)
1404→			matrixes[i] = val.(Matrix)
1405→
1406→			// Keep a copy of the original point slices so that they
1407→			// can be returned to the pool.
1408→			origMatrixes[i] = make(Matrix, len(matrixes[i]))
1409→			copy(origMatrixes[i], matrixes[i])
1410→		}
1411→	}
1412→
1413→	vectors := make([]Vector, len(exprs)) // Input vectors for the function.
1414→	// Create an output vector that is as big as the input matrix with
1415→	// the most time series.
1416→	biggestLen := 1
1417→	for i := range exprs {
1418→		vectors[i] = make(Vector, 0, len(matrixes[i]))
1419→		if len(matrixes[i]) > biggestLen {
1420→			biggestLen = len(matrixes[i])
1421→		}
1422→	}
1423→	enh := &EvalNodeHelper{Out: make(Vector, 0, biggestLen), enableDelayedNameRemoval: ev.enableDelayedNameRemoval}
1424→	type seriesAndTimestamp struct {
1425→		Series
1426→		ts int64
1427→	}
1428→	seriess := make(map[uint64]seriesAndTimestamp, biggestLen) // Output series by series hash.
1429→	tempNumSamples := ev.currentSamples
1430→
1431→	var (
1432→		seriesHelpers [][]EvalSeriesHelper
1433→		bufHelpers    [][]EvalSeriesHelper // Buffer updated on each step
1434→	)
1435→
1436→	if useSignatures {
1437→		var (
1438→			// Function to compute the join signature for each series.
1439→			sigf  func(labels.Labels) string
1440→			buf   = make([]byte, 0, 1024)
1441→			names = slices.Clone(matching.MatchingLabels)
1442→		)
1443→		if matching.On {
1444→			slices.Sort(names)
1445→			sigf = func(lset labels.Labels) string {
1446→				return string(lset.BytesWithLabels(buf, names...))
1447→			}
1448→		} else { // "without"
1449→			names = append([]string{labels.MetricName}, names...)
1450→			slices.Sort(names)
1451→			sigf = func(lset labels.Labels) string {
1452→				return string(lset.BytesWithoutLabels(buf, names...))
1453→			}
1454→		}
1455→
1456→		seriesHelpers = make([][]EvalSeriesHelper, len(exprs))
1457→		bufHelpers = make([][]EvalSeriesHelper, len(exprs))
1458→
1459→		signatureToOrdinal := make(map[string]int)
1460→
1461→		for i := range exprs {
1462→			seriesHelpers[i] = make([]EvalSeriesHelper, len(matrixes[i]))
1463→			bufHelpers[i] = make([]EvalSeriesHelper, len(matrixes[i]))
1464→
1465→			for si, series := range matrixes[i] {
1466→				strSig := sigf(series.Metric)
1467→
1468→				if sigOrd, ok := signatureToOrdinal[strSig]; ok {
1469→					seriesHelpers[i][si] = EvalSeriesHelper{sigOrdinal: sigOrd}
1470→					continue
1471→				}
1472→
1473→				signatureToOrdinal[strSig] = enh.numSigs
1474→				seriesHelpers[i][si] = EvalSeriesHelper{sigOrdinal: enh.numSigs}
1475→				enh.numSigs++
1476→			}
1477→		}
1478→	}
1479→
1480→	for ts := ev.startTimestamp; ts <= ev.endTimestamp; ts += ev.interval {
1481→		if err := contextDone(ctx, "expression evaluation"); err != nil {
1482→			ev.error(err)
1483→		}
1484→		// Reset number of samples in memory after each timestamp.
1485→		ev.currentSamples = tempNumSamples
1486→		// Gather input vectors for this timestamp.
1487→		for i := range exprs {
1488→			var bh []EvalSeriesHelper
1489→			var sh []EvalSeriesHelper
1490→			if useSignatures {
1491→				bh = bufHelpers[i][:0]
1492→				sh = seriesHelpers[i]
1493→			}
1494→			vectors[i], bh = ev.gatherVector(ts, matrixes[i], vectors[i], bh, sh)
1495→			if useSignatures {
1496→				bufHelpers[i] = bh
1497→			}
1498→		}
1499→
1500→		// Make the function call.
1501→		enh.Ts = ts
1502→		result, ws := funcCall(vectors, nil, bufHelpers, enh)
1503→		enh.Out = result[:0] // Reuse result vector.
1504→		warnings.Merge(ws)
1505→
1506→		vecNumSamples := result.TotalSamples()
1507→		ev.currentSamples += vecNumSamples
1508→		// When we reset currentSamples to tempNumSamples during the next iteration of the loop it also
1509→		// needs to include the samples from the result here, as they're still in memory.
1510→		tempNumSamples += vecNumSamples
1511→		ev.samplesStats.UpdatePeak(ev.currentSamples)
1512→
1513→		if ev.currentSamples > ev.maxSamples {
1514→			ev.error(ErrTooManySamples(env))
1515→		}
1516→
1517→		// If this could be an instant query, shortcut so as not to change sort order.
1518→		if ev.endTimestamp == ev.startTimestamp {
1519→			if !ev.enableDelayedNameRemoval && result.ContainsSameLabelset() {
1520→				ev.errorf("vector cannot contain metrics with the same labelset")
1521→			}
1522→			mat := make(Matrix, len(result))
1523→			for i, s := range result {
1524→				if s.H == nil {
1525→					mat[i] = Series{Metric: s.Metric, Floats: []FPoint{{T: ts, F: s.F}}, DropName: s.DropName}
1526→				} else {
1527→					mat[i] = Series{Metric: s.Metric, Histograms: []HPoint{{T: ts, H: s.H}}, DropName: s.DropName}
1528→				}
1529→			}
1530→			ev.currentSamples = originalNumSamples + mat.TotalSamples()
1531→			ev.samplesStats.UpdatePeak(ev.currentSamples)
1532→			return mat, warnings
1533→		}
1534→
1535→		// Add samples in output vector to output series.
1536→		for _, sample := range result {
1537→			h := sample.Metric.Hash()
1538→			ss, ok := seriess[h]
1539→			if ok {
1540→				if ss.ts == ts { // If we've seen this output series before at this timestamp, it's a duplicate.
1541→					ev.errorf("vector cannot contain metrics with the same labelset")
1542→				}
1543→				ss.ts = ts
1544→			} else {
1545→				ss = seriesAndTimestamp{Series{Metric: sample.Metric, DropName: sample.DropName}, ts}
1546→			}
1547→			addToSeries(&ss.Series, enh.Ts, sample.F, sample.H, numSteps)
1548→			seriess[h] = ss
1549→		}
1550→	}
1551→
1552→	// Reuse the original point slices.
1553→	for _, m := range origMatrixes {
1554→		for _, s := range m {
1555→			putFPointSlice(s.Floats)
1556→			putHPointSlice(s.Histograms)
1557→		}
1558→	}
1559→	// Assemble the output matrix. By the time we get here we know we don't have too many samples.
1560→	mat := make(Matrix, 0, len(seriess))
1561→	for _, ss := range seriess {
1562→		mat = append(mat, ss.Series)
1563→	}
1564→	ev.currentSamples = originalNumSamples + mat.TotalSamples()
1565→	ev.samplesStats.UpdatePeak(ev.currentSamples)
1566→	return mat, warnings
1567→}
