1569→func (ev *evaluator) rangeEvalAgg(ctx context.Context, aggExpr *parser.AggregateExpr, sortedGrouping []string, inputMatrix Matrix, params *fParams) (Matrix, annotations.Annotations) {
1570→	// Keep a copy of the original point slice so that it can be returned to the pool.
1571→	origMatrix := slices.Clone(inputMatrix)
1572→	defer func() {
1573→		for _, s := range origMatrix {
1574→			putFPointSlice(s.Floats)
1575→			putHPointSlice(s.Histograms)
1576→		}
1577→	}()
1578→
1579→	var annos annotations.Annotations
1580→
1581→	enh := &EvalNodeHelper{enableDelayedNameRemoval: ev.enableDelayedNameRemoval}
1582→	tempNumSamples := ev.currentSamples
1583→
1584→	// Create a mapping from input series to output groups.
1585→	buf := make([]byte, 0, 1024)
1586→	groupToResultIndex := make(map[uint64]int)
1587→	seriesToResult := make([]int, len(inputMatrix))
1588→	var result Matrix
1589→
1590→	groupCount := 0
1591→	for si, series := range inputMatrix {
1592→		var groupingKey uint64
1593→		groupingKey, buf = generateGroupingKey(series.Metric, sortedGrouping, aggExpr.Without, buf)
1594→		index, ok := groupToResultIndex[groupingKey]
1595→		// Add a new group if it doesn't exist.
1596→		if !ok {
1597→			if aggExpr.Op != parser.TOPK && aggExpr.Op != parser.BOTTOMK && aggExpr.Op != parser.LIMITK && aggExpr.Op != parser.LIMIT_RATIO {
1598→				m := generateGroupingLabels(enh, series.Metric, aggExpr.Without, sortedGrouping)
1599→				result = append(result, Series{Metric: m})

1900→	}
