1904→// eval evaluates the given expression as the given AST expression node requires.
1905→func (ev *evaluator) eval(ctx context.Context, expr parser.Expr) (parser.Value, annotations.Annotations) {
1906→	// This is the top-level evaluation method.
1907→	// Thus, we check for timeout/cancellation here.
1908→	if err := contextDone(ctx, "expression evaluation"); err != nil {
1909→		ev.error(err)
1910→	}
1911→
1912→	if ev.endTimestamp < ev.startTimestamp {
1913→		return Matrix{}, nil
1914→	}
1915→
1916→	numSteps := int((ev.endTimestamp-ev.startTimestamp)/ev.interval) + 1
1917→
1918→	// Create a new span to help investigate inner evaluation performances.
1919→	ctx, span := otel.Tracer("").Start(ctx, stats.InnerEvalTime.SpanOperation()+" eval "+reflect.TypeOf(expr).String())
1920→	defer span.End()
1921→	if ss, ok := expr.(interface{ ShortString() string }); ok {
1922→		span.SetAttributes(attribute.String("operation", ss.ShortString()))
1923→	}
1924→
1925→	switch e := expr.(type) {
1926→	case *parser.AggregateExpr:
1927→		// Grouping labels must be sorted (expected both by generateGroupingKey() and aggregation()).
1928→		sortedGrouping := e.Grouping
1929→		slices.Sort(sortedGrouping)
1930→
1931→		if e.Op == parser.COUNT_VALUES {
1932→			valueLabel := e.Param.(*parser.StringLiteral)
1933→			if !model.UTF8Validation.IsValidLabelName(valueLabel.Val) {
1934→				ev.errorf("invalid label name %s", valueLabel)
1935→			}
1936→			if !e.Without {
1937→				sortedGrouping = append(sortedGrouping, valueLabel.Val)
1938→				slices.Sort(sortedGrouping)
1939→			}
1940→			return ev.rangeEval(ctx, nil, func(v []Vector, _ Matrix, _ [][]EvalSeriesHelper, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
1941→				return ev.aggregationCountValues(e, sortedGrouping, valueLabel.Val, v[0], enh)
1942→			}, e.Expr)
1943→		}
1944→
1945→		var warnings annotations.Annotations
1946→		originalNumSamples := ev.currentSamples
1947→		// e.Param is the number k for topk/bottomk, or q for quantile.
1948→		fp, ws := newFParams(ctx, ev, e.Param)
1949→		warnings.Merge(ws)
1950→		// Now fetch the data to be aggregated.
1951→		val, ws := ev.eval(ctx, e.Expr)
1952→		warnings.Merge(ws)
1953→		inputMatrix := val.(Matrix)
1954→
1955→		result, ws := ev.rangeEvalAgg(ctx, e, sortedGrouping, inputMatrix, fp)
1956→		warnings.Merge(ws)
1957→		ev.currentSamples = originalNumSamples + result.TotalSamples()
1958→		ev.samplesStats.UpdatePeak(ev.currentSamples)
1959→
1960→		return result, warnings
1961→
1962→	case *parser.Call:
1963→		call := FunctionCalls[e.Func.Name]
1964→		if e.Func.Name == "timestamp" {
1965→			// Matrix evaluation always returns the evaluation time,
1966→			// so this function needs special handling when given
1967→			// a vector selector.
1968→			arg := unwrapStepInvariantExpr(e.Args[0])
1969→			vs, ok := arg.(*parser.VectorSelector)
1970→			if ok {
1971→				return ev.rangeEvalTimestampFunctionOverVectorSelector(ctx, vs, call, e)
1972→			}
1973→		}
1974→
1975→		// Check if the function has a matrix argument.
1976→		var (
1977→			matrixArgIndex int
1978→			matrixArg      bool
1979→			warnings       annotations.Annotations
1980→		)
1981→		for i := range e.Args {
1982→			a := e.Args[i]
1983→			if _, ok := a.(*parser.MatrixSelector); ok {
1984→				matrixArgIndex = i
1985→				matrixArg = true
1986→				break
1987→			}
1988→			// parser.SubqueryExpr can be used in place of parser.MatrixSelector.
1989→			if subq, ok := a.(*parser.SubqueryExpr); ok {
1990→				matrixArgIndex = i
1991→				matrixArg = true
1992→				// Replacing parser.SubqueryExpr with parser.MatrixSelector.
1993→				val, totalSamples, ws := ev.evalSubquery(ctx, subq)
1994→				e.Args[i] = val
1995→				warnings.Merge(ws)
1996→				defer func() {
1997→					// subquery result takes space in the memory. Get rid of that at the end.
1998→					val.VectorSelector.(*parser.VectorSelector).Series = nil
1999→					ev.currentSamples -= totalSamples
2000→				}()
2001→				break
2002→			}
2003→		}
2004→
2005→		// Special handling for functions that work on series not samples.
2006→		switch e.Func.Name {
2007→		case "label_replace":
2008→			return ev.evalLabelReplace(ctx, e.Args)
2009→		case "label_join":
2010→			return ev.evalLabelJoin(ctx, e.Args)
2011→		case "info":
2012→			return ev.evalInfo(ctx, e.Args)
2013→		}
2014→
2015→		if !matrixArg {
2016→			// Does not have a matrix argument.
2017→			return ev.rangeEval(ctx, nil, func(v []Vector, _ Matrix, _ [][]EvalSeriesHelper, enh *EvalNodeHelper) (Vector, annotations.Annotations) {
2018→				vec, annos := call(v, nil, e.Args, enh)
2019→				return vec, warnings.Merge(annos)
2020→			}, e.Args...)
2021→		}
2022→
2023→		// Evaluate any non-matrix arguments.
2024→		evalVals := make([]Matrix, len(e.Args))
2025→		for i, e := range e.Args {
2026→			if i != matrixArgIndex {
2027→				val, ws := ev.eval(ctx, e)
2028→				evalVals[i] = val.(Matrix)
2029→				warnings.Merge(ws)
2030→			}
2031→		}
2032→
2033→		arg := e.Args[matrixArgIndex]
2034→		sel := arg.(*parser.MatrixSelector)
2035→		selVS := sel.VectorSelector.(*parser.VectorSelector)
2036→
2037→		switch {
2038→		case selVS.Anchored:
2039→			if _, ok := AnchoredSafeFunctions[e.Func.Name]; !ok {
2040→				ev.errorf("anchored modifier can only be used with: %s - not with %s", strings.Join(slices.Sorted(maps.Keys(AnchoredSafeFunctions)), ", "), e.Func.Name)
2041→			}
2042→		case selVS.Smoothed:
2043→			if _, ok := SmoothedSafeFunctions[e.Func.Name]; !ok {
2044→				ev.errorf("smoothed modifier can only be used with: %s - not with %s", strings.Join(slices.Sorted(maps.Keys(SmoothedSafeFunctions)), ", "), e.Func.Name)
2045→			}
2046→		}
2047→
2048→		ws, err := checkAndExpandSeriesSet(ctx, sel)
2049→		warnings.Merge(ws)
2050→		if err != nil {
2051→			ev.error(errWithWarnings{fmt.Errorf("expanding series: %w", err), warnings})
2052→		}
2053→		mat := make(Matrix, 0, len(selVS.Series)) // Output matrix.
2054→		offset := durationMilliseconds(selVS.Offset)
2055→		selRange := durationMilliseconds(sel.Range)
2056→
2057→		var stepRange int64
2058→		switch {
2059→		case selVS.Anchored:
2060→			stepRange = min(selRange+durationMilliseconds(ev.lookbackDelta), ev.interval)
2061→		case selVS.Smoothed:
2062→			stepRange = min(selRange+durationMilliseconds(2*ev.lookbackDelta), ev.interval)
2063→		default:
2064→			stepRange = min(selRange, ev.interval)
2065→		}
2066→
2067→		// Reuse objects across steps to save memory allocations.
2068→		var floats []FPoint
2069→		var histograms []HPoint
2070→		var prevSS *Series
2071→		inMatrix := make(Matrix, 1)
2072→		enh := &EvalNodeHelper{Out: make(Vector, 0, 1), enableDelayedNameRemoval: ev.enableDelayedNameRemoval}
