2413→		res, ws := newEv.eval(ctx, e.Expr)
2414→		ev.currentSamples = newEv.currentSamples
2415→		ev.samplesStats.UpdatePeakFromSubquery(newEv.samplesStats)
2416→		for ts, step := ev.startTimestamp, -1; ts <= ev.endTimestamp; ts += ev.interval {
