2465→// reuseOrGetHPointSlices reuses the space from previous slice to create new slice if the former has lots of room.
2466→// The previous slices capacity is adjusted so when it is re-used from the pool it doesn't overflow into the new one.
2467→func reuseOrGetHPointSlices(prevSS *Series, numSteps int) (r []HPoint) {
2468→	if prevSS != nil && cap(prevSS.Histograms)-2*len(prevSS.Histograms) > 0 {
2469→		r = prevSS.Histograms[len(prevSS.Histograms):]
2470→		prevSS.Histograms = prevSS.Histograms[0:len(prevSS.Histograms):len(prevSS.Histograms)]
2471→		return r
2472→	}
2473→
2474→	return getHPointSlice(numSteps)
2475→}
